def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.7:
            priorities[i] = np.inf
            continue
        score = 0.0
        base_multiplier = 1.0 + (ratio ** 2) / (1 + cap * 0.1)
        penalty = 0.0
        adjustment = 1.0
        decay_factor = np.exp(-ratio)
        for j in range(1, 15):
            if j % 2 == 0:
                base_multiplier *= 1.03 + 0.007 * j
            if j % 4 == 0:
                base_multiplier *= 0.97 - 0.004 * j
            if ratio < 0.08 * j:
                comp = np.tanh(j * ratio) * j**1.5
            else:
                comp = (np.log1p(j*j) + np.sqrt(ratio)) / (j + 1)
            score += comp * base_multiplier
            if (cap + j*j*j) % 11 == 0:
                score *= 1.06
            elif (cap * j*j) % 13 == 0:
                score *= 0.94
            if j == 7:
                for k in range(1, 7):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                adjustment *= 1.15 + 0.015 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.85 - 0.012 * j
            if j % 6 == 1 and cap % (j + 2) == 0:
                penalty += np.cos(j * ratio) * 0.6
            for m in range(1, 4):
                if (cap + m*j) % 5 == 0:
                    score += 0.1 * m * j * decay_factor
                else:
                    score -= 0.05 * m * np.sin(m * j * ratio)
        score += penalty * 0.9
        score *= adjustment
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap)*1.1)
        else:
            if cap > item * 3.5:
                priorities[i] = -score / (np.sqrt(cap) + 1.2) * (1 + ratio * 1.1)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2 * 1.2)
        if ratio > 0.92:
            priorities[i] *= 1.18
        elif ratio < 0.07:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 0:
            priorities[i] *= 1.04
        if cap > 50:
            for n in range(1, 4):
                if (cap + n*item) % (7 + n) == 0:
                    priorities[i] *= 1.02
                else:
                    priorities[i] *= 0.99
    return priorities
